import { formatAmount } from '@/utils/utils';
import Token from '@/models/Token';
import { CityLedgerService, type MyClTx } from '@/services/city-ledger';
import { PropertyService } from '@/services/property.service';
import { Component, Host, Prop, State, h } from '@stencil/core';
import type { IProperty } from '@/models/property';
import moment from 'moment';

const DATE_DISPLAY = 'MMM DD, YYYY';

@Component({
  tag: 'ir-cl-invoice-preview',
  styleUrl: 'ir-cl-invoice-preview.css',
  shadow: true,
})
export class IrClInvoicePreview {
  @Prop() propertyId: number;
  @Prop() ticket: string;
  @Prop() baseurl: string;
  @Prop() fromDate: string;
  @Prop() toDate: string;
  @Prop() agentId: number;
  @Prop() agentName: string;
  @Prop() documentNumber: string;

  @State() private isLoading: boolean = false;
  @State() private error: string | null = null;
  @State() private property: IProperty | null = null;
  @State() private transactions: MyClTx[] = [];

  private tokenService = new Token();
  private propertyService = new PropertyService();
  private cityLedgerService = new CityLedgerService();

  componentWillLoad() {
    if (!this.ticket) {
      this.error = 'Authentication ticket is required.';
      return;
    }
    if (this.baseurl) this.tokenService.setBaseUrl(this.baseurl);
    this.tokenService.setToken(this.ticket);
    return this.fetchData();
  }

  private async fetchData() {
    this.isLoading = true;
    this.error = null;
    try {
      const start = this.fromDate ?? moment().subtract(2, 'years').format('YYYY-MM-DD');
      const end = this.toDate ?? moment().format('YYYY-MM-DD');

      const [propertyData, clResult] = await Promise.all([
        this.propertyService.getExposedProperty({ id: this.propertyId, language: 'en' }),
        this.cityLedgerService.fetchCL({
          AGENCY_ID: this.agentId,
          START_DATE: start,
          END_DATE: end,
          START_ROW: 0,
          END_ROW: 1000,
          SEARCH_QUERY: this.documentNumber,
        }),
      ]);

      this.property = propertyData?.My_Result ?? null;
      this.transactions = clResult?.My_Cl_tx ?? [];
    } catch (e: any) {
      this.error = e?.message ?? 'Failed to load invoice data.';
    } finally {
      this.isLoading = false;
    }
  }

  private get totals() {
    return this.transactions.reduce(
      (acc, tx) => ({
        net: acc.net + (tx.NET_AMOUNT ?? 0),
        tax: acc.tax + (tx.TAX_AMOUNT ?? 0),
        total: acc.total + (tx.TOTAL_AMOUNT ?? 0),
        debit: acc.debit + (tx.DEBIT ?? 0),
        credit: acc.credit + (tx.CREDIT ?? 0),
      }),
      { net: 0, tax: 0, total: 0, debit: 0, credit: 0 },
    );
  }

  private get currencySymbol(): string {
    return this.property?.currency?.symbol ?? '$';
  }

  private get primaryContact() {
    return this.property?.contacts?.find(c => c.type === 'marketing') ?? this.property?.contacts?.[0];
  }

  private renderMoney(amount: number) {
    return formatAmount(this.currencySymbol, amount);
  }

  private renderHeader() {
    const p = this.property;
    const logo = p?.space_theme?.logo;
    return (
      <header class="invoice-header">
        <div class="invoice-header__property">
          {logo && <img class="invoice-header__logo" src={logo} alt={p?.name} />}
          <div class="invoice-header__property-info">
            <h1 class="invoice-header__property-name">{p?.name}</h1>
            {p?.address && <p class="invoice-header__address">{p.address}</p>}
            {p?.city && <p class="invoice-header__address">{(p.city as any)?.name}</p>}
            {p?.country && <p class="invoice-header__address">{p.country?.name}</p>}
            {p?.phone && <p class="invoice-header__contact">{p.phone}</p>}
            {this.primaryContact?.email && <p class="invoice-header__contact">{this.primaryContact.email}</p>}
            {p?.tax_nbr && <p class="invoice-header__tax-nbr">Tax Reg: {p.tax_nbr}</p>}
          </div>
        </div>
        <div class="invoice-header__meta">
          <h2 class="invoice-header__title">INVOICE</h2>
          {this.documentNumber && (
            <div class="invoice-header__meta-row">
              <span class="invoice-header__meta-label">Document #</span>
              <span class="invoice-header__meta-value">{this.documentNumber}</span>
            </div>
          )}
          <div class="invoice-header__meta-row">
            <span class="invoice-header__meta-label">Date</span>
            <span class="invoice-header__meta-value">{moment().format(DATE_DISPLAY)}</span>
          </div>
          {(this.fromDate || this.toDate) && (
            <div class="invoice-header__meta-row">
              <span class="invoice-header__meta-label">Period</span>
              <span class="invoice-header__meta-value">
                {this.fromDate ? moment(this.fromDate).format(DATE_DISPLAY) : '—'} –{' '}
                {this.toDate ? moment(this.toDate).format(DATE_DISPLAY) : '—'}
              </span>
            </div>
          )}
        </div>
      </header>
    );
  }

  private renderBillTo() {
    if (!this.agentName) return null;
    return (
      <section class="invoice-bill-to">
        <p class="invoice-bill-to__label">Bill To</p>
        <p class="invoice-bill-to__name">{this.agentName}</p>
      </section>
    );
  }

  private renderLineItems() {
    return (
      <section class="invoice-items">
        <table class="invoice-items__table">
          <thead>
            <tr>
              <th class="invoice-items__th">#</th>
              <th class="invoice-items__th">Description</th>
              <th class="invoice-items__th">Guest</th>
              <th class="invoice-items__th">Booking</th>
              <th class="invoice-items__th">Stay</th>
              <th class="invoice-items__th invoice-items__th--num">Charges</th>
              <th class="invoice-items__th invoice-items__th--num">Payments</th>
            </tr>
          </thead>
          <tbody>
            {this.transactions.length === 0 ? (
              <tr>
                <td class="invoice-items__empty" colSpan={7}>
                  No transactions found for this document.
                </td>
              </tr>
            ) : (
              this.transactions.map((tx, i) => (
                <tr key={tx.CL_TX_ID} class="invoice-items__row">
                  <td class="invoice-items__td invoice-items__td--index">{i + 1}</td>
                  <td class="invoice-items__td">{tx.DESCRIPTION || '—'}</td>
                  <td class="invoice-items__td">
                    {tx.GUEST_FIRST_NAME} {tx.GUEST_LAST_NAME}
                  </td>
                  <td class="invoice-items__td invoice-items__td--booking">{tx.BOOK_NBR}</td>
                  <td class="invoice-items__td invoice-items__td--dates">
                    {tx.FROM_DATE ? moment(tx.FROM_DATE).format(DATE_DISPLAY) : '—'}
                    {tx.TO_DATE ? ` – ${moment(tx.TO_DATE).format(DATE_DISPLAY)}` : ''}
                  </td>
                  <td class="invoice-items__td invoice-items__td--num">{tx.DEBIT ? this.renderMoney(tx.DEBIT) : '—'}</td>
                  <td class="invoice-items__td invoice-items__td--num">{tx.CREDIT ? this.renderMoney(tx.CREDIT) : '—'}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </section>
    );
  }

  private renderTotals() {
    const t = this.totals;
    return (
      <section class="invoice-totals">
        <div class="invoice-totals__grid">
          <span class="invoice-totals__label">Net Amount</span>
          <span class="invoice-totals__value">{this.renderMoney(t.net)}</span>

          <span class="invoice-totals__label">Taxes</span>
          <span class="invoice-totals__value">{this.renderMoney(t.tax)}</span>

          <div class="invoice-totals__divider"></div>
          <div class="invoice-totals__divider"></div>

          <span class="invoice-totals__label invoice-totals__label--total">Total</span>
          <span class="invoice-totals__value invoice-totals__value--total">{this.renderMoney(t.total)}</span>
        </div>
      </section>
    );
  }

  render() {
    if (!this.ticket) {
      return (
        <Host>
          <div class="invoice-state invoice-state--error">Authentication ticket is required.</div>
        </Host>
      );
    }

    if (this.isLoading) {
      return (
        <Host>
          <div class="invoice-state">
            <ir-spinner></ir-spinner>
          </div>
        </Host>
      );
    }

    if (this.error) {
      return (
        <Host>
          <div class="invoice-state invoice-state--error">{this.error}</div>
        </Host>
      );
    }

    return (
      <Host>
        <div class="invoice">
          {this.renderHeader()}
          <hr class="invoice-divider" />
          {this.renderBillTo()}
          {this.renderLineItems()}
          {this.renderTotals()}
        </div>
      </Host>
    );
  }
}
